// Voxel Slime — a classic cute RPG slime monster.
// A rounded gooey aqua-green dome with a CLEAN happy face on the front.
// Orientation (verified): the camera looks at the (+X,-Y) corner, which points
// at the viewer. So the face is placed along that corner: a "slide" s runs from
// the -Y face (s<0, left) through the corner (s=0) to the +X face (s>0, right),
// and z is height. Features are placed as chunky surface blocks (2 deep) so they
// stay legible after light smoothing.
// Symmetric placement about s=0. Z-up, sits on z=0. ~14 voxels tall.
const { voxels } = api;
const v = voxels();

// ---- palette ----
const GEL    = '#3fce9f';  // main slime body
const GEL_D  = '#2a9b78';  // darker base rim / shadow
const GEL_DD = '#1d7058';  // deepest base ring
const GEL_L  = '#7fe6c2';  // lit upper dome
const SHEEN  = '#eafff8';  // bright gooey highlight sheen
const SHEEN2 = '#c2f4e3';  // softer sheen edge
const EYEC   = '#13241f';  // dark happy eyes
const EYEHI  = '#f4fcf9';  // eye catch-light
const MOUTH  = '#13241f';  // smile (same dark as eyes)

// ============ BLOB BODY ============
// Teardrop dome: wide bulbous base rounding up to a domed crown.
v.sphere([0, 0, 4], 9, GEL);     // wide base bulge
v.sphere([0, 0, 8], 7, GEL);     // mid dome
v.sphere([0, 0, 11], 4, GEL);    // rounded crown
// chop below ground so it sits flat on z=0
for (let x = -10; x <= 10; x++)
  for (let y = -10; y <= 10; y++)
    for (let z = -10; z < 0; z++) v.remove(x, y, z);

// ---- height shading: lit crown, mid body, deep base rim ----
v.forEach((x, y, z, c) => {
  if (z >= 11) v.set(x, y, z, GEL_L);          // lit crown
  else if (z >= 4) v.set(x, y, z, GEL);        // mid body
  else if (z >= 2) v.set(x, y, z, GEL_D);      // base rim shadow
  else v.set(x, y, z, GEL_DD);                 // deepest base ring
});

// ============ FACE — on the front (+X,-Y) corner ============
// Walk inward from outside along the corner normal (+1,-1) for slide s and
// height z; the first occupied voxel is the front surface. Paint it AND the
// voxel just behind it the feature color so it's 2-deep and survives smoothing.
// Walk inward along the corner normal (+1,-1) at sub-voxel slide `s`; return the
// first occupied voxel [x, y, depth].
function cornerSurface(s, z) {
  for (let d = 14; d >= -2; d -= 0.5) {
    const x = Math.round((d + s) * 0.7071);
    const y = Math.round((-d + s) * 0.7071);
    if (v.has(x, y, z)) return [x, y, d];
  }
  return null;
}
// Paint a contiguous feature: sample the slide range [s0,s1] densely so every
// surface voxel across that arc is hit (no gaps), and color the surface voxel
// plus the one just behind it (2 deep) so it survives smoothing.
function faceArc(s0, s1, z, color) {
  for (let s = s0; s <= s1 + 1e-6; s += 0.34) {
    const p = cornerSurface(s, z);
    if (!p) continue;
    const [x, y, d] = p;
    v.set(x, y, z, color);
    const x2 = Math.round((d - 1 + s) * 0.7071);
    const y2 = Math.round((-(d - 1) + s) * 0.7071);
    if (v.has(x2, y2, z)) v.set(x2, y2, z, color);
  }
}
function face(s, z, color) { faceArc(s, s, z, color); }

// Two big round eyes, symmetric about s=0, with a clear bare gap (s -2..2).
// Each eye is a solid connected arc, two rows tall (z 8,9) -> even, round, happy.
for (const z of [8, 9]) { faceArc(-4.0, -2.7, z, EYEC); faceArc(2.7, 4.0, z, EYEC); }
// white catch-light: a sparkle in the upper-outer of each eye
face(-3.6, 9, EYEHI); face(3.6, 9, EYEHI);

// One clean BIG upturned smile: a connected U — wide flat dark bottom across
// center (z=4), corners lifting two steps (z=5,6) toward the eyes for max cheer.
faceArc(-2.4, 2.4, 4, MOUTH);                            // wide flat bottom
face(-3, 5, MOUTH); face(3, 5, MOUTH);                   // corners lift
face(-3.4, 6, MOUTH); face(3.4, 6, MOUTH);              // corners curl up to eyes

// ============ SHEEN (bright glossy patch high on the dome, up-left) ============
for (const z of [12, 13]) faceArc(-4.2, -2.6, z, SHEEN);
face(-2, 13, SHEEN2); face(-4, 14, SHEEN2);

// Light smoothing for the gooey read; few iterations so the face stays crisp.
return v.smooth({ iterations: 2 });
